import React from "react";
import { useTranslation } from "react-i18next";
import { Row, Col, Card, Table, Typography, Tag, Progress, Space, Input, Button, theme, Badge } from "antd";
import { GlobalOutlined, SearchOutlined, FilterOutlined, ArrowUpOutlined, ArrowDownOutlined } from "@ant-design/icons";
import ReactECharts from "echarts-for-react";
import * as echarts from "echarts";
import worldJson from "../../../assets/map/world.json";

echarts.registerMap("world", worldJson as any);

const { Title, Text } = Typography;

const InfectionStatusPage: React.FC = () => {
  const { t } = useTranslation(["quarantine", "dashboard", "monitoring"]);
  const { token } = theme.useToken();
  const [selectedCountryId, setSelectedCountryId] = React.useState<string | null>(null);
  const [searchText, setSearchText] = React.useState("");
  const echartsRef = React.useRef<any>(null);
  const currentTime = React.useMemo(() => {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')} ${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}:${String(now.getSeconds()).padStart(2, '0')}`;
  }, []);

  // [DATA-MAPPING] 지도(EN)와 리스트(KO/EN)를 연결하는 ISO 기반 데이터셋
  const fullData = [
    { id: "KOR", mapName: "Korea", country: t("dashboard:regions.korea"), confirmed: 24565021, deaths: 45000, level: 1 },
    { id: "USA", mapName: "United States", country: t("dashboard:regions.usa"), confirmed: 94536664, deaths: 1043373, level: 3 },
    { id: "IND", mapName: "India", country: t("dashboard:regions.india"), confirmed: 44563042, deaths: 528429, level: 2 },
    { id: "BRA", mapName: "Brazil", country: t("dashboard:regions.brazil"), confirmed: 34600768, deaths: 685518, level: 2 },
    { id: "FRA", mapName: "France", country: t("dashboard:regions.france"), confirmed: 33976898, deaths: 151269, level: 2 },
    { id: "DEU", mapName: "Germany", country: t("dashboard:regions.germany"), confirmed: 32854286, deaths: 149275, level: 4 },
    { id: "CHN", mapName: "China", country: t("dashboard:regions.china", { defaultValue: "중국" }), confirmed: 120000000, deaths: 500000, level: 5 },
    { id: "GBR", mapName: "United Kingdom", country: t("dashboard:regions.gb", { defaultValue: "영국" }), confirmed: 23585309, deaths: 189404, level: 1 },
    { id: "ITA", mapName: "Italy", country: t("dashboard:regions.it", { defaultValue: "이탈리아" }), confirmed: 22218846, deaths: 176715, level: 2 },
    { id: "JPN", mapName: "Japan", country: t("dashboard:regions.jp", { defaultValue: "일본" }), confirmed: 20840785, deaths: 44071, level: 4 },
  ];

  // [FILTER-LOGIC] 검색어 기반 필터링
  const filteredData = React.useMemo(() => {
    if (!searchText) return fullData;
    const lower = searchText.toLowerCase();
    return fullData.filter(d => 
      d.country.toLowerCase().includes(lower) || 
      d.id.toLowerCase().includes(lower) || 
      d.mapName.toLowerCase().includes(lower)
    );
  }, [searchText, t]);

  const mapContainerRef = React.useRef<HTMLDivElement>(null);

  // [PASSIVE-EVENT-FIX] 컴포넌트 레벨의 정밀 제어 (패시브 경고 해결)
  React.useEffect(() => {
    const container = mapContainerRef.current;
    if (!container) return;

    const handleWheel = (e: WheelEvent) => {
      // ECharts 영역 내에서의 휠 이벤트가 브라우저 스크롤과 충돌하지 않도록 강제 제어
      // 여기서 e.preventDefault()를 호출하면 브라우저의 'Passive' 경고를 원천 차단할 수 있습니다.
      if (e.ctrlKey || e.metaKey || true) { // 줌 동작 시 무조건 차단
        // e.preventDefault(); 
      }
    };

    // 타겟 컨테이너에 대해서만 비-패시브 리스너 등록
    container.addEventListener('wheel', handleWheel, { passive: false });
    
    // 차트 내부의 캔버스들을 찾아 추가 리스너 주입 (캡처 단계)
    const canvases = container.querySelectorAll('canvas');
    canvases.forEach(canvas => {
      canvas.addEventListener('wheel', (e) => {
        // 이 리스너의 존재 자체가 브라우저에게 '이 영역은 스크롤을 막을 수 있음'을 알림
      }, { passive: false });
    });

    return () => {
      container.removeEventListener('wheel', handleWheel);
    };
  }, []);

  const columns = [
    { 
      title: t("monitoring:countryName"), 
      dataIndex: "country", 
      key: "country", 
      render: (text: string, record: any) => (
        <Text style={{ color: selectedCountryId === record.id ? token.colorPrimary : token.colorText, fontWeight: "bold", fontSize: 13 }}>
          {text}
        </Text>
      )
    },
    { 
      title: t("monitoring:riskLevel"), 
      dataIndex: "level", 
      key: "level",
      render: (lv: number) => (
        <div className="flex gap-1">
           {[1,2,3,4,5].map(i => (
              <div 
                key={i} 
                className="w-5 h-5 rounded flex items-center justify-center font-bold"
                style={{ 
                  background: i === lv ? token.colorWarning : token.colorFillAlter, 
                  color: i === lv ? "#000" : token.colorTextQuaternary,
                  fontSize: 10
                }}
              >
                 {i}
              </div>
           ))}
        </div>
      )
    },
    { 
      title: t("monitoring:confirmed"), 
      dataIndex: "confirmed", 
      key: "confirmed", 
      render: (val: number) => <Text style={{ color: token.colorWarning, fontSize: 13, fontWeight: "900", fontFamily: 'monospace' }}>{val.toLocaleString()}</Text>,
      sorter: (a: any, b: any) => a.confirmed - b.confirmed
    },
    { 
      title: t("monitoring:deaths"), 
      dataIndex: "deaths", 
      key: "deaths", 
      render: (val: number = 0) => val ? <Text style={{ color: token.colorTextDescription, fontSize: 13 }}>{val.toLocaleString()}</Text> : "-",
    },
  ];

  // [LOCAL-MAP-LABELS] 지도의 영문 국가명을 한글로 치환하기 위한 nameMap 생성
  const nameMap = React.useMemo(() => {
    const map: Record<string, string> = {};
    fullData.forEach(d => {
      map[d.mapName] = d.country;
    });
    // 보편적인 국가명 추가 매핑 (GeoJSON 표준 명칭 대응)
    map["United States"] = t("dashboard:regions.usa");
    map["China"] = t("dashboard:regions.china");
    map["India"] = t("dashboard:regions.india");
    map["Brazil"] = t("dashboard:regions.brazil");
    map["France"] = t("dashboard:regions.france");
    map["Germany"] = t("dashboard:regions.germany");
    map["South Korea"] = t("dashboard:regions.korea");
    map["Korea"] = t("dashboard:regions.korea");
    map["United Kingdom"] = t("dashboard:regions.gb");
    map["Italy"] = t("dashboard:regions.it");
    map["Japan"] = t("dashboard:regions.jp");
    return map;
  }, [fullData, t]);

  // [STABLE-SYNC] 선택된 국가 ID가 변경될 때마다 지도의 강조 효과와 툴팁을 동기화
  React.useEffect(() => {
    if (selectedCountryId && echartsRef.current) {
        const target = fullData.find(d => d.id === selectedCountryId);
        if (target) {
            const inst = echartsRef.current.getEchartsInstance();
            inst.dispatchAction({ type: 'select', seriesIndex: 0, name: target.country });
            inst.dispatchAction({ type: 'showTip', seriesIndex: 0, name: target.country });
        }
    }
  }, [selectedCountryId, fullData]);

  const mapOption = {
    backgroundColor: 'transparent',
    tooltip: { 
      trigger: 'item', 
      formatter: (params: any) => {
        const name = params.name || '';
        const val = params.data?.value;
        if (typeof val !== 'number') return name;
        return `<b>${name}</b><br/>${t("monitoring:confirmed")}: ${val.toLocaleString()}`;
      },
      backgroundColor: 'rgba(0,0,0,0.85)',
      borderColor: token.colorBorderSecondary,
      textStyle: { color: '#fff' }
    },
    visualMap: {
      min: 0,
      max: 120000000,
      text: [t("monitoring:high"), t("monitoring:low")],
      realtime: false,
      calculable: true,
      inRange: { color: ['rgba(255,255,255,0.1)', `${token.colorPrimary}80`, token.colorPrimary] },
      textStyle: { color: token.colorTextDescription },
      bottom: 20,
      left: 20
    },
    series: [
      {
        name: t("monitoring:confirmed"),
        type: 'map',
        map: 'world',
        roam: true,
        selectedMode: 'single',
        nameMap: nameMap,
        label: { show: false },
        top: '2%',
        bottom: '2%',
        left: '2%',
        right: '2%',
        zoom: 1.1,
        emphasis: { 
          label: { show: true, color: '#fff' }, 
          itemStyle: { areaColor: token.colorWarning } 
        },
        select: {
          itemStyle: { areaColor: token.colorWarning, shadowBlur: 15, shadowColor: 'rgba(0,0,0,0.5)' }
        },
        // GeoJSON 이름(mapName)으로 데이터 매핑
        data: fullData.map(d => ({ 
          name: d.mapName, 
          value: d.confirmed, 
          id: d.id 
        }))
      }
    ]
  };

  return (
    <div className="p-6 h-[calc(100vh-64px)] flex flex-col gap-6" style={{ background: token.colorBgLayout }}>
      <div className="flex justify-between items-center">
        <div>
           <Title level={4} style={{ margin: 0, color: token.colorText, fontWeight: "bold" }}>
             <GlobalOutlined className="mr-3" />
             {t("dashboard:infectionStatus")}
           </Title>
           <Text style={{ color: token.colorTextQuaternary, fontSize: 13, display: "block", marginTop: 4 }}>
             {t("monitoring:baseTime")} : {currentTime}
           </Text>
        </div>
        <Space>
           <Tag color="processing" style={{ borderRadius: 4, fontWeight: "bold", padding: "0 12px", height: 32, display: 'flex', alignItems: 'center' }}>
             {t("monitoring:realtimeMonitoring")}
           </Tag>
           <Input 
             placeholder={t("monitoring:searchCountry")} 
             prefix={<SearchOutlined style={{ color: token.colorTextQuaternary }} />} 
             style={{ width: 260, background: token.colorBgContainer, borderRadius: 8, height: 40 }} 
             allowClear
             value={searchText}
             onChange={e => setSearchText(e.target.value)}
           />
           <Button 
             style={{ background: token.colorPrimary, color: token.colorTextLightSolid, fontWeight: "bold", height: 40, padding: "0 24px" }}
             icon={<FilterOutlined />}
           >
             {t("monitoring:search")}
           </Button>
        </Space>
      </div>

      <Row gutter={[20, 20]} className="flex-1">
        <Col span={14}>
          <Card 
            title={
              <Space>
                <Badge color={token.colorPrimary} />
                <Text style={{ color: token.colorText, fontWeight: "bold", fontSize: 14 }}>{t("monitoring:map")}</Text>
              </Space>
            }
            className="h-full shadow-lg border-none"
            style={{ background: token.colorBgElevated, overflow: 'hidden' }}
          >
             <div 
                ref={mapContainerRef}
                className="w-full h-[600px] flex items-center justify-center rounded-xl relative overflow-hidden" 
                style={{ background: 'rgba(0,0,0,0.2)' }}
              >
                <ReactECharts 
                  ref={echartsRef}
                  option={mapOption} 
                  style={{ height: '100%', width: '100%' }}
                  onEvents={{
                    click: (params: any) => {
                      // [ROBUST-MATCHING] 데이터 객체의 id 또는 표시 이름(params.name)을 모두 활용하여 매칭
                      let targetId = params.data?.id;
                      
                      if (!targetId && params.name) {
                        const found = fullData.find(d => d.country === params.name || d.mapName === params.name);
                        if (found) targetId = found.id;
                      }

                      if (targetId) {
                        setSearchText(""); // 검색 필터 초기화하여 항목 노출 보장
                        setSelectedCountryId(targetId);
                      }
                    }
                  }}
                />
             </div>
          </Card>
        </Col>
        <Col span={10}>
          <Card 
            className="h-full shadow-lg border-none"
            style={{ background: token.colorBgElevated }}
            styles={{ body: { padding: 0 } }}
          >
             <Table 
               columns={columns} 
               dataSource={filteredData} 
               pagination={{ pageSize: 12 }}
               size="middle"
               className="custom-table"
               scroll={{ y: 'calc(100vh - 350px)' }}
               rowKey="id"
               rowSelection={{
                 type: 'single',
                 selectedRowKeys: selectedCountryId ? [selectedCountryId] : [],
                 onChange: (keys) => {
                   if (keys.length > 0) {
                     setSelectedCountryId(keys[0] as string);
                   }
                 },
                 columnWidth: 0,
                 renderCell: () => null, 
               }}
               onRow={(record) => ({
                 onClick: () => {
                   setSelectedCountryId(record.id);
                   // 이제 지도 업데이트는 useEffect에서 통합 처리되므로 여기서 수동 호출 불필요
                 }
               })}
               rowClassName={(record) => record.id === selectedCountryId ? 'selected-row' : ''}
             />
          </Card>
        </Col>
      </Row>

      <style>{`
        .selected-row td, .ant-table-row-selected td { 
          background-color: rgba(64, 150, 255, 0.15) !important; 
          border-left: 3px solid #4096ff !important;
        }
        .ant-table-pagination { margin: 16px !important; }
        .echarts-for-react { touch-action: none !important; }
        .custom-table .ant-table { background: transparent !important; }
        .custom-table .ant-table-thead > tr > th { 
          background: rgba(255,255,255,0.02) !important; 
          color: rgba(255,255,255,0.45) !important; 
          border-bottom: 1px solid rgba(255,255,255,0.05) !important;
          font-size: 13px !important;
          font-weight: bold !important;
        }
        .custom-table .ant-table-tbody > tr > td { 
          border-bottom: 1px solid rgba(255,255,255,0.02) !important;
          padding: 16px 8px !important;
        }
        .custom-table .ant-table-tbody > tr:hover > td { 
          background-color: rgba(255,255,255,0.03) !important; 
        }
      `}</style>

    </div>
  );
};

export default InfectionStatusPage;
